INSERT INTO leis_ordinarias_2026 (numero_lei, data_publicacao, ementa, link_planalto) VALUES
('15.357', '20/03/2026', 'Altera a Lei nº 5.991, de 17 de dezembro de 1973, para dispor sobre a comercialização de medicamentos em farmácia ou drogaria instalada na área de venda de supermercados.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/lei/L15357.htm'),
('15.356', '19/03/2026', 'Altera a Lei nº 13.999, de 18 de maio de 2020, para autorizar a utilização de recursos não comprometidos do FGO para a cobertura de operações contratadas no âmbito do Pronaf.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/lei/L15356.htm'),
('15.355', '11/03/2026', 'Institui a Política de Acolhimento e Manejo de Animais Resgatados (Amar); e altera as Leis nºs 9.605/1998, 12.334/2010 e 12.340/2010.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/lei/L15355.htm'),
('15.354', '10/03/2026', 'Institui a Semana Nacional de Retiros Culturais.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/lei/L15354.htm'),
('15.353', '08/03/2026', 'Altera o Código Penal para prever a presunção absoluta de vulnerabilidade da vítima do crime de estupro de vulnerável e para estabelecer a aplicação das penas independentemente da experiência sexual da vítima.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/lei/L15353.htm'),
('15.352', '25/02/2026', 'Transforma cargos no âmbito do Poder Executivo federal; altera a LGPD para dispor sobre a ANPD; cria a Carreira de Regulação e Fiscalização de Proteção de Dados; altera o Estatuto Digital da Criança e do Adolescente.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/lei/L15352.htm'),
('15.351', '17/02/2026', 'Altera a Lei nº 10.356/2001, que dispõe sobre o quadro de pessoal e o plano de carreira do Tribunal de Contas da União; e revoga a Lei nº 11.854/2008.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/lei/L15351.htm'),
('15.350', '17/02/2026', 'Altera a Lei nº 12.300/2010, para modificar o Plano de Carreira dos Servidores do Senado Federal.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/lei/L15350.htm'),
('15.349', '17/02/2026', 'Dispõe sobre a modernização da Carreira Legislativa da Câmara dos Deputados e sobre a reestruturação da remuneração com base em critérios de desempenho, competências, metas e resultados.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/lei/L15349.htm'),
('15.348', '13/02/2026', 'Altera a Lei nº 14.237/2021 para modificar a denominação do Auxílio Gás dos Brasileiros para Auxílio Gás do Povo, criar modalidades de operacionalização e instituir o Programa Nacional de Acesso ao Cozimento Limpo.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/lei/L15348.htm'),
('15.347', '06/02/2026', 'Abre crédito extraordinário em favor do Ministério da Agricultura e Pecuária, no valor de R$ 83.500.000,00.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/lei/L15347.htm'),
('15.346', '14/01/2026', 'Estima a receita e fixa a despesa da União para o exercício financeiro de 2026.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/lei/L15346.htm'),
('15.345', '12/01/2026', 'Regulamenta o exercício profissional de acupuntura.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/lei/L15345.htm'),
('15.344', '12/01/2026', 'Institui a Política Nacional de Indução à Docência na Educação Básica - Mais Professores para o Brasil.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/lei/L15344.htm'),
('15.343', '09/01/2026', 'Altera a Lei nº 13.240/2015, para ampliar as hipóteses de destinação não onerosa de imóveis não operacionais do Fundo do Regime Geral de Previdência Social.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/lei/L15343.htm'),
('15.342', '09/01/2026', 'Institui o Dia Nacional da Lei Seca.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/lei/L15342.htm'),
('15.341', '09/01/2026', 'Autoriza o Poder Executivo federal, por meio do Ministério da Defesa, a doar materiais de natureza militar do Comando do Exército para a República do Paraguai.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/lei/L15341.htm'),
('15.340', '09/01/2026', 'Denomina "Odilon Vitorino de Siqueira" a ponte sobre o Rio Tarauacá, localizada no km 535,5 da Rodovia BR-364, no Município de Tarauacá, no Estado do Acre.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/lei/L15340.htm'),
('15.339', '09/01/2026', 'Denomina "Ponte Hélio Nogueira Lopes" a ponte sobre o Rio São Francisco que interliga os Municípios de Penedo (AL) e Neópolis (SE), na Rodovia BR-349.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/lei/L15339.htm'),
('15.338', '09/01/2026', 'Autoriza o Poder Executivo federal a doar aeronaves da Polícia Federal à República do Paraguai e da Marinha do Brasil à República Oriental do Uruguai.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/lei/L15338.htm'),
('15.337', '08/01/2026', 'Altera a Lei nº 13.710/2018 (Política Nacional de Incentivo à Produção de Cacau de Qualidade), para promover a ampliação do mercado do cacau e o fomento da produção sustentável do cacaueiro no Brasil.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/lei/L15337.htm'),
('15.336', '08/01/2026', 'Altera a Lei nº 14.232/2021, para determinar a publicação periódica de relatórios do Registro Unificado de Dados e Informações sobre Violência contra as Mulheres.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/lei/L15336.htm'),
('15.335', '08/01/2026', 'Altera a Lei nº 6.615/1978, para disciplinar a emissão da carteira profissional de Radialista.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/lei/L15335.htm'),
('15.334', '08/01/2026', 'Institui o Dia Nacional de Luto e de Memória às Mulheres Vítimas de Feminicídio.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/lei/L15334.htm'),
('15.333', '07/01/2026', 'Altera a Lei nº 10.257/2001 (Estatuto da Cidade), para incluir diretriz de política urbana relativa à construção, instalação, sinalização, higienização e conservação de equipamentos de uso coletivo.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/lei/L15333.htm'),
('15.332', '07/01/2026', 'Confere ao Município de Maringá, no Estado do Paraná, o título de Capital Nacional do Associativismo.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/lei/L15332.htm'),
('15.331', '07/01/2026', 'Institui o Mês Nacional das Olimpíadas Científicas e do Conhecimento, a ser celebrado, anualmente, no mês de julho.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/lei/L15331.htm'),
('15.330', '07/01/2026', 'Altera o art. 1º da Lei nº 11.675/2008, para designar o açaí como fruta nacional.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/lei/L15330.htm'),
('15.329', '07/01/2026', 'Altera o Decreto-Lei nº 401/1968, para dispor sobre a responsabilidade pela retenção e pelo recolhimento do Imposto sobre a Renda na fonte incidente sobre os juros remetidos para o exterior.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/lei/L15329.htm'),
('15.328', '07/01/2026', 'Institui o Dia Nacional do Sociólogo.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/lei/L15328.htm'),
('15.327', '06/01/2026', 'Veda descontos relativos a mensalidades associativas nos benefícios administrados pelo INSS; estabelece busca ativa a beneficiários lesados e prevê o seu ressarcimento.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/lei/L15327.htm'),
('15.326', '06/01/2026', 'Altera a Lei nº 11.738/2008, para incluir os professores da educação infantil como profissionais do magistério, e a LDB para definir professores da educação infantil.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/lei/L15326.htm'),
('15.325', '06/01/2026', 'Dispõe sobre o exercício da profissão de multimídia.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/lei/L15325.htm'),
('15.324', '06/01/2026', 'Altera as Leis nºs 9.472/1997 e 9.295/1996, para assegurar a prestação dos serviços de telecomunicações por cooperativas.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/lei/L15324.htm');
